import React from 'react';
import { Card, CardContent, Box, Typography, Stack, CircularProgress } from '@mui/material';
import response from './response.json';

interface CurrentEpisode {
  title: string;
  host: string;
  duration: string;
  progress: string;
  completionPercent: number;
}

interface ListeningStats {
  totalTimeListened: string;
  episodesCompleted: number;
  favoriteGenre: string;
}

interface PodcastData {
  currentEpisode: CurrentEpisode;
  listeningStats: ListeningStats;
}

export default function Widget() {
  const podcastData = response.data as PodcastData;
  const { currentEpisode, listeningStats } = podcastData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#333', color: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: response.meta.primaryColor }}>
              Now Playing
            </Typography>
            <Typography variant="body2" sx={{ mt: 0.5 }}>
              {currentEpisode.title}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Hosted by {currentEpisode.host}
            </Typography>
            <Stack direction="row" spacing={1} alignItems="center" sx={{ mt: 1 }}>
              <CircularProgress variant="determinate" value={currentEpisode.completionPercent} size={40} sx={{ color: response.meta.accentColor }} />
              <Typography variant="body2" color="text.secondary">
                {currentEpisode.progress} / {currentEpisode.duration}
              </Typography>
            </Stack>
          </Box>

          <Box>
            <Typography variant="h6" sx={{ color: response.meta.primaryColor }}>
              Your Stats
            </Typography>
            <Stack spacing={1} sx={{ mt: 1 }}>
              <Typography variant="body2">
                Total Time Listened: {listeningStats.totalTimeListened}
              </Typography>
              <Typography variant="body2">
                Episodes Completed: {listeningStats.episodesCompleted}
              </Typography>
              <Typography variant="body2">
                Favorite Genre: {listeningStats.favoriteGenre}
              </Typography>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
